-- deployment: Creating doctor_master_id...
CREATE TRIGGER doctor_master_id
BEFORE INSERT ON doctor_master
FOR EACH ROW
BEGIN
    IF NEW.id IS NULL OR NEW.id = '' THEN
        SET NEW.id = UUID();
    END IF;
END;


